map<long long,long long> memo;

long long solve(long long x) {
    if (x < 2) return 0;
    if (memo.count(x)) return memo[x];
    return memo[x] = x + solve(x / 2) + solve((x + 1) / 2);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;
    cout << solve(n) << '\n';
    return 0;
